                                            {icon.bookmarkAction && (
                                                <div onClick={(e) => icon.bookmarkAction(e, journal.id)} id="card-icons" className={`${icon.className} ${bouncingBookmarkId === journal.id ? 'bookmark-bouncing' : ''}`}>
